// NewListChallengesPayload builds a authz service listChallenges endpoint
// payload.
func NewListChallengesPayload(outcome *string, principalUrn *string, scope *string, projectID *string, resolved *bool, limit int, offset int, apikeyToken *string, sessionToken *string) *authz.ListChallengesPayload {
	v := &authz.ListChallengesPayload{}
	v.Outcome = outcome
	v.PrincipalUrn = principalUrn
	v.Scope = scope
	v.ProjectID = projectID
	v.Resolved = resolved
	v.Limit = limit
	v.Offset = offset
	v.ApikeyToken = apikeyToken
	v.SessionToken = sessionToken

	return v
}

// NewResolveChallengePayload builds a authz service resolveChallenge endpoint
// payload.
func NewResolveChallengePayload(body *ResolveChallengeRequestBody, apikeyToken *string, sessionToken *string) *authz.ResolveChallengePayload {
	v := &authz.ResolveChallengePayload{
		ChallengeID:    *body.ChallengeID,
		PrincipalUrn:   *body.PrincipalUrn,
		Scope:          *body.Scope,
		ResourceKind:   body.ResourceKind,
		ResourceID:     body.ResourceID,
		ResolutionType: *body.ResolutionType,
		RoleSlug:       body.RoleSlug,
	}
	v.ApikeyToken = apikeyToken
	v.SessionToken = sessionToken

	return v
}

// ValidateResolveChallengeRequestBody runs the validations defined on
// ResolveChallengeRequestBody
func ValidateResolveChallengeRequestBody(body *ResolveChallengeRequestBody) (err error) {
	if body.ChallengeID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("challenge_id", "body"))
	}
	if body.PrincipalUrn == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("principal_urn", "body"))
	}
	if body.Scope == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("scope", "body"))
	}
	if body.ResolutionType == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("resolution_type", "body"))
	}
	if body.ResolutionType != nil {
		if !(*body.ResolutionType == "role_assigned" || *body.ResolutionType == "dismissed") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.resolution_type", *body.ResolutionType, []any{"role_assigned", "dismissed"}))
		}
	}
	return
}
